class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.size(), res = 0;
        for (int d = 1; d * d <= n; ++d) {
            if (n % d == 0) {
                int cnt[26] = {0};
                for (int i = 0; i < n; ++i) {
                    cnt[s[i] - 'a']++;
                }
                int mx = 0;
                for (int i = 0; i < 26; ++i) {
                    mx = max(mx, cnt[i] % d);
                }
                res += mx;
            }
        }
        return res;
    }
};
